<?php
namespace Tests\Feature;use App\Models\Character;use App\Models\CharacterItem;use App\Models\CharacterWallet;use App\Models\GoldTransaction;use App\Models\Monster;use App\Models\User;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class SimulateCombatCommandTest extends TestCase{use RefreshDatabase;public function test_command_simulates_without_persistence(){$this->seed(WorldCatalogSeeder::class);$c=Character::factory()->for(User::factory())->create();$before=$c->fresh()->toArray();$m=Monster::where('code','grey_wolf')->firstOrFail();$monster=$m->fresh()->toArray();$this->artisan('game:combat:simulate',['characterId'=>$c->id,'monsterCode'=>'grey_wolf'])->assertExitCode(0);$this->assertSame($before,$c->fresh()->toArray());$this->assertSame($monster,$m->fresh()->toArray());$this->assertSame(0,CharacterItem::count());$this->assertSame(0,CharacterWallet::count());$this->assertSame(0,GoldTransaction::count());}public function test_command_rejects_missing_or_inactive_monster(){$c=Character::factory()->for(User::factory())->create();$this->artisan('game:combat:simulate',['characterId'=>999999,'monsterCode'=>'none'])->assertExitCode(1);$m=Monster::create(['code'=>'inactive','name'=>'Inactive','level'=>1,'max_health'=>1,'attack'=>1,'defense'=>0,'accuracy_rate'=>0,'evasion_rate'=>0,'critical_chance'=>0,'experience_reward'=>0,'status'=>'inactive']);$this->artisan('game:combat:simulate',['characterId'=>$c->id,'monsterCode'=>$m->code])->assertExitCode(1);}}
